import React from "react";
import { HarmonyAlertDialog } from "@/components/ui/harmony-alert-dialog";
import { formatSettingKey } from "../utils";
import type { AppSetting } from "../types";

interface DeleteSettingModalProps {
  deleteTarget: AppSetting;
  onClose: () => void;
  onConfirm: () => void;
  isPending: boolean;
}

export const DeleteSettingModal: React.FC<DeleteSettingModalProps> = ({
  deleteTarget,
  onClose,
  onConfirm,
  isPending,
}) => {
  return (
    <HarmonyAlertDialog
      open
      onOpenChange={(open) => { if (!open) onClose(); }}
      variant="danger"
      title="Delete Configuration Setting"
      description={`This will permanently remove "${formatSettingKey(deleteTarget.key)}". The system will revert to default hardcoded values for this setting. This action is irreversible.`}
      actionLabel="Delete Setting"
      onAction={onConfirm}
      isActioning={isPending}
    />
  );
};
