import React from "react";
import { Loader2 } from "lucide-react";
import HarmonyForm from "@/components/forms/HarmonyForm";
import { Button } from "@/shadcn/components/ui/button";
import { HarmonyDialog } from "@/components/ui/harmony-dialog";
import { PermissionGate } from "@/components/shared/PermissionGate";
import { PERMISSIONS } from "@/constants/permissions";

interface AddSettingModalProps {
  onClose: () => void;
  onSubmit: (formData: any) => void;
  isPending: boolean;
}

export const AddSettingModal: React.FC<AddSettingModalProps> = ({ onClose, onSubmit, isPending }) => {
  return (
    <HarmonyDialog
      open
      onOpenChange={onClose}
      title="Create New Setting"
      description="Override application configuration at runtime"
      footerChildren={
        <div className="flex justify-end gap-3 w-full">
          <Button variant="secondary" onClick={onClose} disabled={isPending}>
            Cancel
          </Button>
          <PermissionGate permission={PERMISSIONS.ApplicationSettings.Update} mode="disable">
            <Button
              disabled={isPending}
              onClick={() => document.querySelector("form")?.requestSubmit?.()}
            >
              {isPending && <Loader2 className="w-4 h-4 animate-spin" />}
              Create Setting
            </Button>
          </PermissionGate>
        </div>
      }
    >
      <HarmonyForm
        dtoName="ApplicationSettingUpsertDTO"
        onSubmit={onSubmit}
        hideSubmitButton={true}
      />
    </HarmonyDialog>
  );
};
