import { useQuery } from "@tanstack/react-query";
import { appSettingsService as accountService } from "@/api/appSettingsService";
import type { AppSetting } from "../types";

export function useAppSettingsData() {
  return useQuery({
    queryKey: ["app-settings-all"],
    queryFn: async () => {
      let allData: AppSetting[] = [];
      let page = 1;
      let hasNext = true;

      while (hasNext) {
        const res = await accountService.getAppSettings(page);
        allData = [...allData, ...(res.data as AppSetting[])];
        hasNext = res.hasNextPage;
        page++;
      }

      return allData;
    },
  });
}
