import { useMutation, useQueryClient } from "@tanstack/react-query";
import { appSettingsService as accountService } from "@/api/appSettingsService";
import { toast } from "sonner";
import type { AppSetting } from "../types";

export function useAppSettingsMutations() {
  const queryClient = useQueryClient();

  const createMutation = useMutation({
    mutationFn: (formData: any) => accountService.createAppSetting(formData),
    onMutate: async (newSetting) => {
      await queryClient.cancelQueries({ queryKey: ["app-settings-all"] });
      const previousSettings = queryClient.getQueryData<AppSetting[]>(["app-settings-all"]);
      queryClient.setQueryData(["app-settings-all"], (old: AppSetting[] | undefined) => [
        ...(old || []),
        { ...newSetting, id: Date.now().toString(), isOptimistic: true },
      ]);
      return { previousSettings };
    },
    onError: (_err, _newSetting, context) => {
      queryClient.setQueryData(["app-settings-all"], context?.previousSettings);
      toast.error("Failed to create setting.");
    },
    onSettled: () => {
      queryClient.invalidateQueries({ queryKey: ["app-settings-all"] });
      toast.success("Action completed successfully!");
    },
  });

  const updateMutation = useMutation({
    mutationFn: ({ key, value }: { key: string; value: string }) =>
      accountService.updateAppSetting(key, { key, value }),
    onMutate: async ({ key, value }) => {
      await queryClient.cancelQueries({ queryKey: ["app-settings-all"] });
      const previousSettings = queryClient.getQueryData<AppSetting[]>(["app-settings-all"]);
      queryClient.setQueryData(["app-settings-all"], (old: AppSetting[] | undefined) =>
        old?.map((setting) => (setting.key === key ? { ...setting, value } : setting))
      );
      return { previousSettings };
    },
    onError: (_err, _variables, context) => {
      queryClient.setQueryData(["app-settings-all"], context?.previousSettings);
      toast.error("Failed to update setting. Rolling back...");
    },
    onSettled: () => {
      queryClient.invalidateQueries({ queryKey: ["app-settings-all"] });
    },
    onSuccess: () => {
      toast.success("Action completed successfully!");
    },
  });

  const deleteMutation = useMutation({
    mutationFn: (key: string) => accountService.deleteAppSetting(key),
    onMutate: async (key) => {
      await queryClient.cancelQueries({ queryKey: ["app-settings-all"] });
      const previousSettings = queryClient.getQueryData<AppSetting[]>(["app-settings-all"]);
      queryClient.setQueryData(["app-settings-all"], (old: AppSetting[] | undefined) =>
        old?.filter((setting) => setting.key !== key)
      );
      return { previousSettings };
    },
    onError: (_err, _key, context) => {
      queryClient.setQueryData(["app-settings-all"], context?.previousSettings);
      toast.error("Failed to delete setting.");
    },
    onSettled: () => {
      queryClient.invalidateQueries({ queryKey: ["app-settings-all"] });
    },
    onSuccess: () => {
      toast.success("Action completed successfully!");
    },
  });

  return {
    createMutation,
    updateMutation,
    deleteMutation,
  };
}
