import { useEffect, useMemo, useRef, useState } from "react";
import { getApiErrorMessage } from "@/api/app/apiError";

// Feature imports
import type { AppSetting, SortBy, SortOrder, SettingsStats as StatsType } from "@/features/settings/types";
import { PAGE_SIZE } from "@/features/settings/constants";
import {
  isBoolean,
  isNumber,
  formatSettingKey,
  formatCategory
} from "@/features/settings/utils";
import { useAppSettingsData } from "@/features/settings/hooks/useAppSettingsData";
import { useAppSettingsMutations } from "@/features/settings/hooks/useAppSettingsMutations";

// Component imports
import { SettingsHeader } from "@/features/settings/components/SettingsHeader";
import { SettingsStats } from "@/features/settings/components/SettingsStats";
import { SettingsControls } from "@/features/settings/components/SettingsControls";
import { SettingsTable } from "@/features/settings/components/SettingsTable";
import { AddSettingModal } from "@/features/settings/components/AddSettingModal";
import { EditSettingModal } from "@/features/settings/components/EditSettingModal";
import { DeleteSettingModal } from "@/features/settings/components/DeleteSettingModal";

export default function ApplicationSettings() {
  const [pageIndex, setPageIndex] = useState(1);
  const [isAddOpen, setIsAddOpen] = useState(false);
  const [deleteTarget, setDeleteTarget] = useState<AppSetting | null>(null);
  const [editTarget, setEditTarget] = useState<AppSetting | null>(null);
  const [editValue, setEditValue] = useState("");

  const [searchTerm, setSearchTerm] = useState("");
  const [categoryFilter, setCategoryFilter] = useState<string>("all");
  const [sortBy, setSortBy] = useState<SortBy>("key");
  const [sortOrder, setSortOrder] = useState<SortOrder>("asc");
  const [revealedSecrets, setRevealedSecrets] = useState<Record<string, boolean>>({});
  const revealTimersRef = useRef<Record<string, ReturnType<typeof setTimeout>>>({});

  const { data, isLoading, error } = useAppSettingsData();
  const { createMutation, updateMutation, deleteMutation } = useAppSettingsMutations();

  const categories = useMemo(() => {
    if (!data) return [];
    const unique = [...new Set(data.map((x) => x.category || "General"))];
    return unique.sort((a, b) => a.localeCompare(b));
  }, [data]);

  const filteredSortedData = useMemo(() => {
    if (!data) return [];
    const term = searchTerm.trim().toLowerCase();

    const filtered = data.filter((setting) => {
      const category = setting.category || "General";
      const byCategory = categoryFilter === "all" || category === categoryFilter;
      if (!byCategory) return false;
      if (!term) return true;

      return (
        String(setting.key || "").toLowerCase().includes(term) ||
        formatSettingKey(String(setting.key || "")).toLowerCase().includes(term) ||
        String(setting.value || "").toLowerCase().includes(term) ||
        String(setting.description || "").toLowerCase().includes(term) ||
        String(category).toLowerCase().includes(term) ||
        formatCategory(String(category)).toLowerCase().includes(term)
      );
    });

    return [...filtered].sort((a, b) => {
      const valA = a[sortBy] ?? "";
      const valB = b[sortBy] ?? "";

      if (typeof valA === "string" && typeof valB === "string") {
        return sortOrder === "asc" ? valA.localeCompare(valB) : valB.localeCompare(valA);
      }
      if (!isNaN(Number(valA)) && !isNaN(Number(valB))) {
        return sortOrder === "asc" ? Number(valA) - Number(valB) : Number(valB) - Number(valA);
      }
      return 0;
    });
  }, [data, searchTerm, categoryFilter, sortBy, sortOrder]);

  const totalPages = Math.max(1, Math.ceil(filteredSortedData.length / PAGE_SIZE));
  const paginatedData = useMemo(() => {
    const start = (pageIndex - 1) * PAGE_SIZE;
    return filteredSortedData.slice(start, start + PAGE_SIZE);
  }, [filteredSortedData, pageIndex]);

  useEffect(() => {
    if (pageIndex > totalPages) setPageIndex(totalPages);
  }, [pageIndex, totalPages]);

  useEffect(() => {
    setPageIndex(1);
  }, [searchTerm, categoryFilter, sortBy, sortOrder]);

  useEffect(() => {
    return () => {
      Object.values(revealTimersRef.current).forEach((timer) => clearTimeout(timer));
    };
  }, []);

  const stats = useMemo<StatsType>(() => {
    const source = data || [];
    return {
      total: source.length,
      readOnly: source.filter((s) => s.isReadOnly).length,
      booleanCount: source.filter((s) => isBoolean(String(s.value))).length,
      numericCount: source.filter((s) => isNumber(String(s.value)) && !isBoolean(String(s.value))).length,
    };
  }, [data]);

  const handleToggle = (setting: AppSetting) => {
    if (setting.isReadOnly) return;
    const newValue = setting.value === "true" ? "false" : "true";
    updateMutation.mutate({ key: setting.key, value: newValue });
  };

  const handleNumberChange = (setting: AppSetting, delta: number) => {
    if (setting.isReadOnly) return;
    const newValue = String(Number(setting.value) + delta);
    updateMutation.mutate({ key: setting.key, value: newValue });
  };

  const handleEditClick = (setting: AppSetting) => {
    setEditTarget(setting);
    setEditValue(setting.value ?? '');
  };

  const confirmEdit = () => {
    if (!editTarget) return;
    updateMutation.mutate({ key: editTarget.key, value: editValue }, {
      onSuccess: () => setEditTarget(null)
    });
  };

  const confirmDelete = () => {
    if (!deleteTarget?.key) return;
    deleteMutation.mutate(deleteTarget.key, {
      onSuccess: () => setDeleteTarget(null)
    });
  };

  const handleRevealToggle = (settingId: string, reveal: boolean) => {
    if (reveal) {
      if (revealTimersRef.current[settingId]) clearTimeout(revealTimersRef.current[settingId]);
      setRevealedSecrets((prev) => ({ ...prev, [settingId]: true }));
      revealTimersRef.current[settingId] = setTimeout(() => {
        setRevealedSecrets((prev) => ({ ...prev, [settingId]: false }));
        delete revealTimersRef.current[settingId];
      }, 5000);
    } else {
      if (revealTimersRef.current[settingId]) {
        clearTimeout(revealTimersRef.current[settingId]);
        delete revealTimersRef.current[settingId];
      }
      setRevealedSecrets((prev) => ({ ...prev, [settingId]: false }));
    }
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center min-h-[600px] bg-muted/30 rounded-3xl border border-dashed border-border">
        <div className="flex flex-col items-center gap-4 p-8 bg-card rounded-2xl shadow-xl ring-1 ring-border">
          <div className="relative">
            <div className="absolute inset-0 rounded-full blur-xl bg-primary/20" />
            <div className="relative rounded-full h-12 w-12 border-[3px] border-border border-t-primary" />
          </div>
          <span className="text-muted-foreground font-semibold tracking-tight">Syncing your configuration...</span>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="max-w-2xl mx-auto p-1 mt-8 overflow-hidden rounded-2xl bg-destructive/10 ring-1 ring-destructive/20 shadow-2xl shadow-destructive/10">
        <div className="p-5 flex items-start gap-4">
          <div className="flex-shrink-0 h-10 w-10 rounded-full bg-destructive/20 flex items-center justify-center text-destructive font-bold">!</div>
          <div>
            <h3 className="font-bold text-destructive text-lg">System Error</h3>
            <p className="text-destructive/80 leading-relaxed mt-1">{getApiErrorMessage(error)}</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="page-wrapper max-w-[1400px] mx-auto space-y-6">
      <header className="relative">
        <SettingsHeader 
          onAddClick={() => setIsAddOpen(true)} 
          isPending={createMutation.isPending} 
        />
      </header>

      <section className="grid grid-cols-1 gap-6">
        <SettingsStats stats={stats} />
      </section>

      <div className="space-y-6">
        <div className="px-2">
            <SettingsControls
                searchTerm={searchTerm}
                setSearchTerm={setSearchTerm}
                categoryFilter={categoryFilter}
                setCategoryFilter={setCategoryFilter}
                categories={categories}
                sortBy={sortBy}
                setSortBy={setSortBy}
                sortOrder={sortOrder}
                setSortOrder={setSortOrder}
            />
        </div>

        <section className="bg-card rounded-2xl border border-border shadow-sm overflow-hidden transition-all duration-300 hover:shadow-md">
            <SettingsTable
                data={paginatedData}
                revealedSecrets={revealedSecrets}
                onRevealToggle={handleRevealToggle}
                onToggle={handleToggle}
                onNumberChange={handleNumberChange}
                onEditClick={handleEditClick}
                onDeleteClick={(s) => setDeleteTarget(s)}
                isUpdatePending={updateMutation.isPending}
            />
        </section>

        {/* Improved Pagination Component */}
        <section className="flex justify-center pt-4 pb-10">
            <nav className="flex items-center gap-1 p-1.5 bg-card/60 backdrop-blur-md border border-border rounded-2xl shadow-sm">
                <button
                    disabled={pageIndex === 1}
                    onClick={() => setPageIndex((prev) => prev - 1)}
                    className="group px-4 py-2 text-sm font-bold text-muted-foreground rounded-xl hover:bg-card hover:text-primary hover:shadow-sm disabled:opacity-25 disabled:hover:bg-transparent disabled:hover:text-muted-foreground transition-all duration-200"
                >
                    <span className="flex items-center gap-1">
                        ← <span className="hidden sm:inline">Previous</span>
                    </span>
                </button>

                <div className="flex items-center gap-2 px-5 py-2 mx-1 bg-muted/50 rounded-xl border border-border">
                    <span className="text-[10px] uppercase tracking-widest font-black text-muted-foreground">Page</span>
                    <div className="flex items-center gap-1.5">
                        <span className="text-sm font-black text-primary tabular-nums">{pageIndex}</span>
                        <span className="text-xs font-bold text-border">/</span>
                        <span className="text-sm font-bold text-foreground tabular-nums">{totalPages}</span>
                    </div>
                </div>

                <button
                    disabled={pageIndex === totalPages}
                    onClick={() => setPageIndex((prev) => prev + 1)}
                    className="group px-4 py-2 text-sm font-bold text-muted-foreground rounded-xl hover:bg-card hover:text-primary hover:shadow-sm disabled:opacity-25 disabled:hover:bg-transparent disabled:hover:text-muted-foreground transition-all duration-200"
                >
                    <span className="flex items-center gap-1">
                        <span className="hidden sm:inline">Next</span> →
                    </span>
                </button>
            </nav>
        </section>
      </div>

      {/* Modals Layer */}
      {isAddOpen && (
        <AddSettingModal
          onClose={() => setIsAddOpen(false)}
          onSubmit={(formData) => createMutation.mutate(formData, { onSuccess: () => setIsAddOpen(false) })}
          isPending={createMutation.isPending}
        />
      )}

      {editTarget && (
        <EditSettingModal
          editTarget={editTarget}
          editValue={editValue}
          setEditValue={setEditValue}
          onClose={() => setEditTarget(null)}
          onConfirm={confirmEdit}
          isPending={updateMutation.isPending}
        />
      )}

      {deleteTarget && (
        <DeleteSettingModal
          deleteTarget={deleteTarget}
          onClose={() => setDeleteTarget(null)}
          onConfirm={confirmDelete}
          isPending={deleteMutation.isPending}
        />
      )}
    </div>
  );
}