import React from "react";
import { Edit3, Eye, EyeOff, Lock, Trash2 } from "lucide-react";
import { PermissionGate } from "@/components/shared/PermissionGate";
import { PERMISSIONS } from "@/constants/permissions";
import {
  formatSettingKey,
  formatCategory,
  isSensitiveSetting,
  maskValue,
  isBoolean,
  isNumber
} from "../utils";
import type { AppSetting } from "../types";
import { TableRow, TableCell } from "@/components/ui";
import { Badge } from "@/shadcn/components/ui/badge";

interface SettingRowProps {
  setting: AppSetting;
  isRevealed: boolean;
  onRevealToggle: (id: string, reveal: boolean) => void;
  onToggle: (setting: AppSetting) => void;
  onNumberChange: (setting: AppSetting, delta: number) => void;
  onEditClick: (setting: AppSetting) => void;
  onDeleteClick: (setting: AppSetting) => void;
  isUpdatePending: boolean;
}

export const SettingRow: React.FC<SettingRowProps> = ({
  setting,
  isRevealed,
  onRevealToggle,
  onToggle,
  onNumberChange,
  onEditClick,
  onDeleteClick,
  isUpdatePending,
}) => {
  const sensitive = isSensitiveSetting(setting);
  const rawValue = String(setting.value ?? "");
  const displayValue = sensitive && !isRevealed ? maskValue(rawValue) : rawValue;
  const settingId = setting.id ?? setting.key;

  return (
    <TableRow className="group/row hover:bg-muted/30 transition-colors">
      <TableCell className="align-middle py-4 px-6">
        <div className="flex flex-col gap-1.5">
          <span className="text-[15px] font-semibold text-foreground tracking-tight leading-snug">
            {formatSettingKey(setting.key)}
          </span>
          <div className="flex items-center gap-3">
            <code className="text-[11px] font-medium text-muted-foreground bg-muted px-2 py-0.5 rounded border border-border tabular-nums">
              {setting.key}
            </code>
            {setting.isReadOnly && (
              <Badge className="bg-transparent text-muted-foreground border-border scale-90 origin-left font-bold uppercase tracking-widest px-1.5 text-[10px] h-auto rounded-full">
                <Lock size={10} className="mr-1" />
                Read Only
              </Badge>
            )}
          </div>
        </div>
      </TableCell>

      <TableCell className="align-middle px-6 max-w-md">
        <p className="text-[13px] font-medium text-muted-foreground leading-relaxed">
          {setting.description || "No description provided for this override."}
        </p>
      </TableCell>

      <TableCell className="align-middle px-6">
        <Badge className="bg-primary/10 text-primary border-primary/20 text-[10px] px-2 py-0.5 h-auto font-bold uppercase tracking-wider rounded-full">
          {formatCategory(setting.category || "")}
        </Badge>
      </TableCell>

      <TableCell className="align-middle px-6 text-center">
        <div className="flex justify-center">
          <PermissionGate permission={PERMISSIONS.ApplicationSettings.Update} mode="disable">
            {isBoolean(setting.value) && (
              <button
                disabled={setting.isReadOnly || isUpdatePending}
                onClick={() => onToggle(setting)}
                className={`relative w-11 h-6 flex items-center rounded-full px-1 transition-all duration-300 ${setting.value === "true" ? "bg-primary shadow-sm" : "bg-muted"
                  }`}
              >
                <div
                  className={`bg-background w-4 h-4 rounded-full shadow-sm transform transition-transform duration-300 ${setting.value === "true" ? "translate-x-5" : "translate-x-0"
                    }`}
                />
              </button>
            )}
          </PermissionGate>

          <PermissionGate permission={PERMISSIONS.ApplicationSettings.Update} mode="disable">
            {isNumber(setting.value) && !isBoolean(setting.value) && (
              <div className="flex items-center gap-1">
                <button
                  disabled={setting.isReadOnly || isUpdatePending}
                  onClick={() => onNumberChange(setting, -1)}
                  className="w-8 h-8 rounded-lg border border-border bg-background text-muted-foreground hover:text-primary hover:border-primary/30 transition-all font-bold shadow-sm"
                >
                  -
                </button>
                <div className="px-3 min-w-[3.5rem] flex flex-col items-center">
                  <span className="text-xs font-black text-foreground tabular-nums">
                    {setting.value}
                  </span>
                  <span className="text-[8px] font-black text-muted-foreground/60 uppercase tracking-tighter -mt-0.5">Value</span>
                </div>
                <button
                  disabled={setting.isReadOnly || isUpdatePending}
                  onClick={() => onNumberChange(setting, 1)}
                  className="w-8 h-8 rounded-lg border border-border bg-background text-muted-foreground hover:text-primary hover:border-primary/30 transition-all font-bold shadow-sm"
                >
                  +
                </button>
              </div>
            )}
          </PermissionGate>

          {!isBoolean(setting.value) && !isNumber(setting.value) && (
            <div className="flex items-center gap-3">
              <span
                className="text-xs font-bold text-foreground px-1 py-2 max-w-[180px] truncate"
                title={displayValue}
              >
                {displayValue}
              </span>

              {sensitive && (
                <button
                  onClick={() => onRevealToggle(settingId, !isRevealed)}
                  className="p-2 text-muted-foreground hover:text-primary hover:bg-primary/10 rounded-xl transition-all"
                >
                  {isRevealed ? <EyeOff size={16} /> : <Eye size={16} />}
                </button>
              )}
            </div>
          )}
        </div>
      </TableCell>

      <TableCell className="align-middle px-6 text-right">
        {!setting.isReadOnly && (
          <div className="flex justify-end gap-2">
            {!isBoolean(setting.value) && !isNumber(setting.value) && (
              <PermissionGate permission={PERMISSIONS.ApplicationSettings.Update} mode="disable">
                <button
                  onClick={() => onEditClick(setting)}
                  className="p-2 text-muted-foreground hover:text-primary hover:bg-primary/10 rounded-xl transition-all"
                  title="Edit Value"
                >
                  <Edit3 size={18} />
                </button>
              </PermissionGate>
            )}
            <PermissionGate permission={PERMISSIONS.ApplicationSettings.Update} mode="disable">
              <button
                onClick={() => onDeleteClick(setting)}
                className="p-2 text-muted-foreground hover:text-destructive hover:bg-destructive/10 rounded-xl transition-all"
                title="Delete Setting"
              >
                <Trash2 size={18} />
              </button>
            </PermissionGate>
          </div>
        )}
      </TableCell>
    </TableRow>
  );
};
