import React from "react";
import type { SettingsStats as StatsType } from "../types";
import { Hash, Lock, ToggleLeft, Binary } from "lucide-react";

interface SettingsStatsProps {
  stats: StatsType;
}

export const SettingsStats: React.FC<SettingsStatsProps> = ({ stats }) => {
  const statConfig = [
    { label: "Total Settings", value: stats.total, icon: <Hash size={18} />, color: "border-t-primary", iconBg: "bg-primary/5", iconText: "text-primary" },
    { label: "Read Only", value: stats.readOnly, icon: <Lock size={18} />, color: "border-t-rose-500", iconBg: "bg-rose-50 dark:bg-rose-950/40", iconText: "text-rose-600 dark:text-rose-400" },
    { label: "Boolean Controls", value: stats.booleanCount, icon: <ToggleLeft size={18} />, color: "border-t-emerald-500", iconBg: "bg-emerald-50 dark:bg-emerald-950/40", iconText: "text-emerald-600 dark:text-emerald-400" },
    { label: "Numeric Controls", value: stats.numericCount, icon: <Binary size={18} />, color: "border-t-blue-500", iconBg: "bg-blue-50 dark:bg-blue-950/40", iconText: "text-blue-600 dark:text-blue-400" },
  ];

  return (
    <section className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
      {statConfig.map((stat, i) => (
        <div key={i} className={`bg-card p-6 rounded-2xl border border-border border-t-4 ${stat.color} shadow-sm flex items-center justify-between group hover:shadow-md transition-all`}>
          <div>
            <p className="text-[10px] uppercase tracking-[0.15em] font-black text-muted-foreground mb-1">
              {stat.label}
            </p>
            <p className="text-3xl font-black text-foreground tabular-nums">
              {stat.value}
            </p>
          </div>
          <div className={`p-3.5 rounded-xl ${stat.iconBg} ${stat.iconText} transition-transform group-hover:scale-110 duration-300`}>
            {stat.icon}
          </div>
        </div>
      ))}
    </section>
  );
};
