import React from "react";
import { Search, SlidersHorizontal } from "lucide-react";
import { formatCategory } from "../utils";
import type { SortBy, SortOrder } from "../types";

interface SettingsControlsProps {
  searchTerm: string;
  setSearchTerm: (val: string) => void;
  categoryFilter: string;
  setCategoryFilter: (val: string) => void;
  categories: string[];
  sortBy: SortBy;
  setSortBy: (val: SortBy) => void;
  sortOrder: SortOrder;
  setSortOrder: (val: SortOrder) => void;
}

export const SettingsControls: React.FC<SettingsControlsProps> = ({
  searchTerm,
  setSearchTerm,
  categoryFilter,
  setCategoryFilter,
  categories,
  sortBy,
  setSortBy,
  sortOrder,
  setSortOrder,
}) => {
  return (
    <section className="rounded-2xl border border-border bg-card p-6 shadow-sm space-y-6">
      <div className="flex items-center gap-3">
        <div className="p-2 bg-primary/10 rounded-xl text-primary">
          <SlidersHorizontal size={16} />
        </div>
        <div className="flex flex-col">
          <span className="text-[10px] font-black text-muted-foreground uppercase tracking-[0.3em] leading-none mb-1">Management Console</span>
          <h3 className="text-base font-black text-foreground tracking-tight">Configuration Explorer</h3>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-4">
        <div className="lg:col-span-5 relative group">
          <Search size={16} className="absolute left-4 top-1/2 -translate-y-1/2 text-muted-foreground" />
          <input
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            placeholder="Search by key, value, domain..."
            className="w-full pl-11 pr-4 py-3 rounded-xl border border-border bg-background text-foreground text-sm font-medium focus:outline-none focus:ring-1 focus:ring-primary/40 transition-all placeholder:text-muted-foreground"
          />
        </div>

        <div className="lg:col-span-3">
          <select
            value={categoryFilter}
            onChange={(e) => setCategoryFilter(e.target.value)}
            className="w-full border border-border rounded-xl px-4 py-3 text-sm font-semibold bg-background text-foreground focus:outline-none focus:ring-1 focus:ring-primary/40 cursor-pointer"
          >
            <option value="all">All Domains</option>
            {categories.map((category) => (
              <option key={category} value={category}>
                {formatCategory(category)}
              </option>
            ))}
          </select>
        </div>

        <div className="lg:col-span-2">
          <select
            value={sortBy}
            onChange={(e) => setSortBy(e.target.value as SortBy)}
            className="w-full border border-border rounded-xl px-4 py-3 text-sm font-semibold bg-background text-foreground focus:outline-none focus:ring-1 focus:ring-primary/40 cursor-pointer"
          >
            <option value="key">Sort: Key</option>
            <option value="value">Sort: Value</option>
            <option value="category">Sort: Domain</option>
          </select>
        </div>

        <div className="lg:col-span-2">
          <button
            onClick={() => setSortOrder(sortOrder === "asc" ? "desc" : "asc")}
            className="w-full px-4 py-3 border border-border rounded-xl text-[10px] font-black uppercase tracking-[0.15em] text-foreground bg-background hover:bg-muted hover:border-border/80 transition-all flex items-center justify-center gap-2 shadow-sm"
          >
            {sortOrder === "asc" ? "Ascending ↑" : "Descending ↓"}
          </button>
        </div>
      </div>
    </section>
  );
};
