import { ACRONYMS, SENSITIVE_KEYWORDS } from "./constants";
import type { AppSetting } from "./types";

export const isBoolean = (val: any) => val === "true" || val === "false";

export const isNumber = (val: any) => typeof val === "string" && !isNaN(Number(val)) && val.trim() !== "";

export const toTitleToken = (token: string) => {
  const lower = token.toLowerCase();
  if (ACRONYMS.has(lower)) return lower.toUpperCase();
  return lower.charAt(0).toUpperCase() + lower.slice(1);
};

export const humanize = (value: string) =>
  value
    .replace(/([a-z0-9])([A-Z])/g, "$1 $2")
    .replace(/[_.\-/]+/g, " ")
    .trim()
    .split(/\s+/)
    .filter(Boolean)
    .map(toTitleToken)
    .join(" ");

export const formatSettingKey = (key?: string) => {
  if (!key) return "Unnamed Setting";
  const segments = key.split(":").map((part) => humanize(part));
  return segments.join(" - ");
};

export const formatCategory = (category?: string) => humanize(category || "General");

export const isSensitiveSetting = (setting: AppSetting) => {
  const haystack = `${setting?.key || ""} ${setting?.category || ""} ${setting?.description || ""}`.toLowerCase();
  return SENSITIVE_KEYWORDS.some((word) => haystack.includes(word));
};

export const maskValue = (value: string) => {
  if (!value) return "";
  if (/^\*+$/.test(value)) return value;
  const maskedLength = Math.max(8, Math.min(16, value.length));
  return "*".repeat(maskedLength);
};
