import React from "react";
import { Info, Loader2 } from "lucide-react";
import CustomQuill from "@/components/ui/CustomQuill";
import { Button } from "@/shadcn/components/ui/button";
import { HarmonyDialog } from "@/components/ui/harmony-dialog";
import { PermissionGate } from "@/components/shared/PermissionGate";
import { PERMISSIONS } from "@/constants/permissions";
import { formatSettingKey } from "../utils";
import type { AppSetting } from "../types";

interface EditSettingModalProps {
  editTarget: AppSetting;
  editValue: string;
  setEditValue: (val: string) => void;
  onClose: () => void;
  onConfirm: () => void;
  isPending: boolean;
}

export const EditSettingModal: React.FC<EditSettingModalProps> = ({
  editTarget,
  editValue,
  setEditValue,
  onClose,
  onConfirm,
  isPending,
}) => {
  return (
    <HarmonyDialog
      open
      onOpenChange={onClose}
      title="Edit Configuration"
      description={formatSettingKey(editTarget.key)}
      footerChildren={
        <div className="flex justify-end gap-3 w-full">
          <Button variant="ghost" onClick={onClose} disabled={isPending}>
            Cancel
          </Button>
          <PermissionGate permission={PERMISSIONS.ApplicationSettings.Update} mode="disable">
            <Button disabled={isPending} onClick={onConfirm}>
              {isPending && <Loader2 className="w-4 h-4 animate-spin" />}
              Save Changes
            </Button>
          </PermissionGate>
        </div>
      }
    >
      <div className="space-y-8 pt-2">
        <div className="space-y-3">
          <label className="text-[10px] font-black text-muted-foreground uppercase tracking-[0.2em] ml-1">
            Override Value
          </label>
          <div className="border border-border rounded-[2rem] overflow-hidden focus-within:ring-8 focus-within:ring-primary/5 transition-all shadow-inner">
            <CustomQuill
              value={editValue}
              onChange={setEditValue}
              placeholder="Enter new configuration value..."
            />
          </div>
        </div>

        <div className="flex items-start gap-4 bg-primary/5 p-5 rounded-[2rem] border border-primary/20">
          <div className="p-1.5 bg-card rounded-lg shadow-sm">
            <Info size={16} className="text-primary" />
          </div>
          <p className="text-xs text-primary font-bold leading-relaxed">
            Updates take effect immediately across all system clusters.
          </p>
        </div>
      </div>
    </HarmonyDialog>
  );
};
